 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→#include "riscv_nn_support.h"
 24→
 25→//// Convolution Functions
 26→int32_t riscv_nn_conv_HWC_s8_s8_s8_RGB_sym_bias_fast(const q7_t * in_tensor,
 27→                                            const uint16_t in_tensor_dim,
 28→                                            const q7_t * ker_weight,
 29→                                            const uint16_t out_tensor_ch,
 30→                                            const uint16_t ker_dim,
 31→                                            const uint16_t pad,
 32→                                            const uint16_t stride,
 33→                                            const q31_t * bias,
 34→                                            const uint16_t pre_rshift,
 35→                                            const uint16_t out_scale,
 36→                                            const uint16_t post_rshift,
 37→                                            q7_t * out_tensor,
 38→                                            const uint16_t out_tensor_dim,
 39→                                            q15_t * in_tmp_buf,
 40→                                            q15_t * wt_tmp_buf)
 41→{
 42→#ifdef ENA_EMPTY_FUN
 43→    //empty body
 44→#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
 45→    long   i_out_y, i_out_x, i_ker_y, i_ker_x;
 46→
 47→    /*
 48→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 49→     *  im2col are done to output in q15_t format from q7_t input
 50→     */
 51→    q7_t *pBuffer = (q7_t *)in_tmp_buf;
 52→    q7_t *pOut = out_tensor;
 53→
 54→    long buf_len = (3 * ker_dim * ker_dim);
 55→    long vl;
 56→
 57→    // This part implements the im2col function
 58→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
 59→    {
 60→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
 61→        {
 62→            // init in_tmp_buf
 63→            long len = buf_len;
 64→            q7_t *pBuffer2 = pBuffer;
 65→            vl = __riscv_vsetvl_e8m8(len);
 66→            vint8m8_t vZero = __riscv_vand(__riscv_vundefined_i8m8(), 0x0, vl);     //const zero for redsum
 67→            while(len > 0)
 68→            {
 69→                __riscv_vse8(pBuffer2, vZero, vl);
 70→                len -= vl;
 71→                pBuffer2 += vl;
 72→                vl = __riscv_vsetvl_e8m8(len);
 73→            }
 74→
 75→            // if (i_ker_y < 0)
 76→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
 77→            {
 78→                pBuffer += ker_dim * 3;
 79→            }
 80→
 81→            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
 82→            for (; i_ker_y < bound_y; i_ker_y++)
 83→            {
 84→                // if (i_ker_x < 0)
 85→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
 86→                {
 87→                    pBuffer += 3;
 88→                }
 89→
 90→                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
 91→                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
 92→                long loop = (bound_x - i_ker_x)*3;
 93→                i_ker_x = bound_x;
 94→                while(loop > 0)
 95→                {
 96→                    vl = __riscv_vsetvl_e8m8(loop);
 97→                    vint8m8_t vpPixel = __riscv_vle8_v_i8m8(pPixel, vl);
 98→                    __riscv_vse8(pBuffer, vpPixel, vl);
 99→                    pPixel += vl;
100→                    pBuffer += vl;
101→                    loop -= vl;
102→                }
103→
104→                // if (i_ker_x >= in_tensor_dim)
105→                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
106→                {
107→                    pBuffer += 3;
108→                }
109→            }
110→
111→            // if (i_ker_y >= in_tensor_dim)
112→            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
113→            {
114→                pBuffer += ker_dim * 3;
115→            }
116→
117→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
118→            {
119→                pOut = nn_mat_mul_kernel_q7_bias_2sft((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, pre_rshift, out_scale, post_rshift, bias, pOut);
120→                pBuffer = (q7_t *)in_tmp_buf;
121→            }
122→        }
123→    }
124→
125→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
126→    if (pBuffer != (q7_t *)in_tmp_buf)
127→    {
128→        unsigned vl;
129→        const q7_t *p_wt = ker_weight;
130→        int       i;
131→        uint16_t  colCnt = 3 * ker_dim * ker_dim;
132→        // long vlenb = NDS_VEC_CSR_GET_VLENB();
133→
134→#if (__clang__)
135→        register const long zero asm ("x0") = 0;
136→#else
137→        register const long zero asm ("x0");
138→#endif
139→
140→        vl = __riscv_vsetvl_e32m1(1);
141→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), zero, vl);     //const zero for redsum
142→
143→        for (i = 0; i < out_tensor_ch; i++)
144→        {
145→            q7_t      *p_in = (q7_t*)in_tmp_buf;
146→            uint16_t colCnt2 = colCnt;
147→
148→            //clear v0~v7
149→            vl = __riscv_vsetvl_e32m8(colCnt);
150→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), zero, vl);
151→
152→            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
153→            // {
154→            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
155→            //     //load src1
156→            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
157→            //     //load src2
158→            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
159→            //     //bump pointers and update loop counter
160→            //     colCnt2 -= vl;
161→            //     p_wt += vl;
162→            //     p_in += vl;
163→            //     //set the proper avl/SEW/LMUL values for vd4dot
164→            //     vl >>= 2;
165→            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
166→            //     //acc += src1 * src2
167→            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
168→            // }
169→
170→            //extra process for the case of elements to be dot producted is not a mutiple of 4
171→            while(colCnt2 > 0)
172→            {
173→                //clean one of the dot product source
174→                vl = __riscv_vsetvlmax_e8m8();
175→                vint8m8_t vP_wt_i8m8 = __riscv_vand(__riscv_vundefined_i8m8(), zero, vl);
176→
177→                vl = __riscv_vsetvl_e8m8(colCnt2);
178→                //load src1
179→                vP_wt_i8m8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8m8, p_wt, vl);
180→                //load src2
181→                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
182→                //bump pointers and update loop counter
183→                colCnt2 -= vl;
184→                p_wt += vl;
185→                p_in += vl;
186→                //set the proper avl/SEW/LMUL values for vd4dot
187→                //remember to deal with the avl of vd4dot is not a multiple of 4 case
188→                vl = __riscv_vsetvl_e32m8(vl);
189→                //acc += src1 * src2
190→                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
191→            }
192→
193→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
194→            vint32m1_t vSum_i32 = __riscv_vredsum(vAccumulator, vZero, vl);
195→
196→            //add bias back
197→            vl = __riscv_vsetvl_e32m1(1);
198→            vint32m1_t vBias_i32 = __riscv_vle32_v_i32m1(bias, vl);
199→            vSum_i32 = __riscv_vadd(vSum_i32, vBias_i32, vl);
200→
201→            //2-stage shift
202→            vSum_i32 = __riscv_vsra(vSum_i32, pre_rshift, vl);
203→            vSum_i32 = __riscv_vmul(vSum_i32, out_scale, vl);
204→            vSum_i32 = __riscv_vadd(vSum_i32, NN_ROUND(post_rshift), vl);
205→
206→            //scale down, clip and store the results
207→            vl = __riscv_vsetvl_e16mf2(1);
208→            vint16mf2_t vSum_i16 = __riscv_vnsra(vSum_i32, post_rshift, vl);
209→            vl = __riscv_vsetvl_e8mf4(1);
210→            vint8mf4_t vSum_i8 = __riscv_vnclip(vSum_i16, zero, __RISCV_VXRM_RNU, vl);
211→            __riscv_vse8(pOut, vSum_i8, vl);
212→            bias += vl;
213→            pOut += vl;
214→        }
215→    }
216→#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
217→    /* left-over because odd number of output pixels */
218→    if (pBuffer != (q7_t *)in_tmp_buf)
219→    {
220→        const q7_t *pA = ker_weight;
221→        long i;
222→        /* basically each time it process 4 entries */
223→        long colCnt = (3 * ker_dim * ker_dim);
224→
225→        //set SEW for 1st time VMV_S_X
226→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
227→        vl = __riscv_vsetvl_e32m8(colCnt);
228→
229→        for (i = 0; i < out_tensor_ch; i++)
230→        {
231→            q31_t sum = bias[i];
232→            q7_t *pB = (q7_t*)in_tmp_buf;
233→            long colCnt2 = colCnt;
234→
235→            //init
236→            vint32m1_t vBias = __riscv_vmv_s_x_i32m1(sum, vl);
237→            //clear v8~v15 (acc)
238→            vint32m8_t vAcc = __riscv_vundefined_i32m8();
239→            vAcc = __riscv_vand_tu(vAcc, vAcc, 0, vl);
240→
241→            while(colCnt2 > 0)
242→            {
243→                vl = __riscv_vsetvl_e8m2(colCnt2);
244→                vint8m2_t vPa_i8 = __riscv_vundefined_i8m2();
245→                vint8m2_t vPb_i8 = __riscv_vundefined_i8m2();
246→                vPa_i8 = __riscv_vle8_tu(vPa_i8, pA, vl);
247→                vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
248→                vAcc = __riscv_vqmacc_vv_i32m8_tu(vAcc, vPa_i8, vPb_i8, vl);
249→                //bump pointers and update loop counter
250→                colCnt2 -= vl;
251→                pA += vl;
252→                pB += vl;
253→            }
254→
255→            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
256→            vint32m1_t vAcc_sum = __riscv_vredsum(vAcc, vBias, vl);
257→            //move vr results to gpr
258→            sum = __riscv_vmv_x(vAcc_sum);
259→
260→            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
261→            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 8);
262→        }
263→    }
264→#endif
265→#elif defined(ENA_VEC_ISA)
266→#ifdef ENA_TILING
267→    //cache is 512KB, type is q7
268→    uint32_t tiling_size = 256;
269→    //num of columnar
270→    int col_counter = 0;
271→    const int in_tensor_ch = 3;
272→    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
273→    unsigned long addr_in_tmp_buf;
274→
275→    /*
276→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
277→     *  im2col are done to output in q15_t format from q7_t input
278→     */
279→    const long align_byte = 64;
280→    q7_t *pBuffer = (q7_t*)in_tmp_buf;
281→    q7_t *pOut = out_tensor;
282→    q31_t *dst_q31;
283→#ifdef DCACHE_SIZE
284→    int i;
285→    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
286→    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / 6); //sqrt(((DCACHE_SIZE) << 10) / 3 / sizeof(float16_t))
287→    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
288→    {
289→        if (tiling_size_arr[i] > max_tile_size_in_cache)
290→        {
291→            tiling_size = tiling_size_arr[i - 1];
292→            break;
293→        }
294→    }
295→#endif
296→#ifdef ENA_8MHVM
297→    char *hvm_base = (char *)0x90000000;
298→    q7_t *src2 = (q7_t *)hvm_base;
299→    addr_in_tmp_buf = (unsigned long)src2 + sizeof(*ker_weight) * in_tensor_ch * ker_dim * ker_dim * out_tensor_ch;
300→#else
301→    q7_t *src2 = (q7_t *)in_tmp_buf
302→                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim * ker_dim; //matrix_A's memory space
303→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
304→    addr_in_tmp_buf = (unsigned long)src2;
305→    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim * ker_dim;
306→#endif
307→    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
308→    dst_q31 = (q31_t *)addr_in_tmp_buf;
309→
310→    /* initial the output */
311→    nn_set_zero_s16((q15_t *)dst_q31, (tiling_size * out_tensor_ch * 2));
312→
313→    // transpose the kernel_weight for matrix multiplication
314→    const long row = out_tensor_ch;
315→    const long col = ker_dim * ker_dim * in_tensor_ch;
316→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
317→
318→    /* This part implements the im256col function */
319→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
320→    {
321→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
322→        {
323→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
324→            {
325→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
326→                {
327→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
328→                    {
329→                        /* Filling 0 for out-of-bound paddings */
330→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
331→                    }
332→                    else
333→                    {
334→                        /* Copying the pixel data to column */
335→                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
336→                    }
337→                    pBuffer += in_tensor_ch;
338→                }
339→            }
340→            col_counter++;
341→
342→            /* Computation is filed for [tiling_size] columns */
343→            if (col_counter == tiling_size)
344→            {
345→                pOut = nn_mat_mul_kernel_tiling_q7((q7_t *)in_tmp_buf,
346→                                                   src2,
347→                                                   dst_q31,
348→                                                   pOut,
349→                                                   col_counter,
350→                                                   in_tensor_ch * ker_dim * ker_dim,
351→                                                   out_tensor_ch,
352→                                                   pre_rshift,
353→                                                   out_scale,
354→                                                   post_rshift,
355→                                                   bias,
356→                                                   tiling_size);
357→                /* reset */
358→                col_counter = 0;
359→                pBuffer = (q7_t *)in_tmp_buf;
360→            }
361→        }
362→    }
363→
364→    /* check if there is left-over for compute */
365→    pOut = nn_mat_mul_kernel_tiling_q7((q7_t*)in_tmp_buf,
366→                                       src2,
367→                                       dst_q31,
368→                                       pOut,
369→                                       col_counter,
370→                                       in_tensor_ch * ker_dim * ker_dim,
371→                                       out_tensor_ch,
372→                                       pre_rshift,
373→                                       out_scale,
374→                                       post_rshift,
375→                                       bias,
376→                                       tiling_size);
377→#else
378→    long   i_out_y, i_out_x, i_ker_y, i_ker_x;
379→
380→    /*
381→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
382→     *  im2col are done to output in q15_t format from q7_t input
383→     */
384→    q7_t *pBuffer = (q7_t *)in_tmp_buf;
385→    q7_t *pOut = out_tensor;
386→
387→    long buf_len = (3 * ker_dim * ker_dim);
388→    long vl;
389→
390→    // This part implements the im2col function
391→    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
392→    {
393→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
394→        {
395→            // init in_tmp_buf
396→            long len = buf_len;
397→            q7_t *pBuffer2 = pBuffer;
398→            NDS_VEC_VSETVLI(vl, len, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
399→            NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0);   //zero
400→            while(len > 0)
401→            {
402→                NDS_VEC_VSB_V(NDS_VEC_V24, pBuffer2);
403→                len -= vl;
404→                pBuffer2 += vl;
405→                NDS_VEC_VSETVLI(vl, len, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
406→            }
407→
408→            // if (i_ker_y < 0)
409→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
410→            {
411→                pBuffer += ker_dim * 3;
412→            }
413→
414→            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim)? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
415→            for (; i_ker_y < bound_y; i_ker_y++)
416→            {
417→                // if (i_ker_x < 0)
418→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
419→                {
420→                    pBuffer += 3;
421→                }
422→
423→                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim)? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
424→                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
425→                long loop = (bound_x - i_ker_x)*3;
426→                i_ker_x = bound_x;
427→                while(loop > 0)
428→                {
429→                    NDS_VEC_VSETVLI(vl, loop, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
430→                    NDS_VEC_VLB_V(NDS_VEC_V0, pPixel);
431→                    NDS_VEC_VSB_V(NDS_VEC_V0, pBuffer);
432→                    pPixel += vl;
433→                    pBuffer += vl;
434→                    loop -= vl;
435→                }
436→
437→                // if (i_ker_x >= in_tensor_dim)
438→                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
439→                {
440→                    pBuffer += 3;
441→                }
442→            }
443→
444→            // if (i_ker_y >= in_tensor_dim)
445→            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
446→            {
447→                pBuffer += ker_dim * 3;
448→            }
449→
450→            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
451→            {
452→                pOut = nn_mat_mul_kernel_q7_bias_2sft((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, pre_rshift, out_scale, post_rshift, bias, pOut);
453→                pBuffer = (q7_t *)in_tmp_buf;
454→            }
455→        }
456→    }
457→
458→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
459→    if (pBuffer != (q7_t *)in_tmp_buf)
460→    {
461→        unsigned vl;
462→        const q7_t *p_wt = ker_weight;
463→        int       i;
464→        uint16_t  colCnt = 3 * ker_dim * ker_dim;
465→        // long vlenb = NDS_VEC_CSR_GET_VLENB();
466→
467→#if (__clang__)
