181→        //add bias to acc
182→        vSum1 = __riscv_vadd(vSum1, vBias, vl);
183→        vSum5 = __riscv_vadd(vSum5, vBias, vl);
184→        vSum9 = __riscv_vadd(vSum9, vBias, vl);
185→        vSum13 = __riscv_vadd(vSum13, vBias, vl);
