189→        vSum5 = __riscv_vsra(vSum5 , pre_rshift, vl);
190→        vSum9 = __riscv_vsra(vSum9 , pre_rshift, vl);
191→        vSum13 = __riscv_vsra(vSum13, pre_rshift, vl);
