193→        vSum1 = __riscv_vmul(vSum1, out_scale, vl);
194→        vSum5 = __riscv_vmul(vSum5, out_scale, vl);
195→        vSum9 = __riscv_vmul(vSum9, out_scale, vl);
196→        vSum13 = __riscv_vmul(vSum13, out_scale, vl);
197→
198→        vSum1 = __riscv_vadd(vSum1, NN_ROUND(post_rshift), vl);
199→        vSum5 = __riscv_vadd(vSum5, NN_ROUND(post_rshift), vl);
200→        vSum9 = __riscv_vadd(vSum9, NN_ROUND(post_rshift), vl);
201→        vSum13 = __riscv_vadd(vSum13, NN_ROUND(post_rshift), vl);
202→
203→        //saturate into 8-bits
204→        vl = __riscv_vsetvl_e16mf2(4);     //4: 4 acc
205→        vint16mf2_t vSum1_i16mf2 = __riscv_vnsra(vSum1, post_rshift, vl);
206→        vint16mf2_t vSum5_i16mf2 = __riscv_vnsra(vSum5, post_rshift, vl);
207→        vint16mf2_t vSum9_i16mf2 = __riscv_vnsra(vSum9, post_rshift, vl);
208→        vint16mf2_t vSum13_i16mf2 = __riscv_vnsra(vSum13, post_rshift, vl);
209→        vl = __riscv_vsetvl_e8mf4(4);     //4: 4 acc
210→        vint8mf4_t vSum1_i8mf4 = __riscv_vnclip(vSum1_i16mf2, 0, __RISCV_VXRM_RNU, vl);
211→        vint8mf4_t vSum5_i8mf4 = __riscv_vnclip(vSum5_i16mf2, 0, __RISCV_VXRM_RNU, vl);
212→        vint8mf4_t vSum9_i8mf4 = __riscv_vnclip(vSum9_i16mf2, 0, __RISCV_VXRM_RNU, vl);
213→        vint8mf4_t vSum13_i8mf4 = __riscv_vnclip(vSum13_i16mf2, 0, __RISCV_VXRM_RNU, vl);
214→
215→        //store the results
216→        __riscv_vse8(out, vSum1_i8mf4, vl);
217→        __riscv_vse8(pOut2, vSum5_i8mf4, vl);
218→        __riscv_vse8(pOut3, vSum9_i8mf4, vl);
219→        __riscv_vse8(pOut4, vSum13_i8mf4, vl);
220→        out += vl;
221→        pOut2 += vl;
222→        pOut3 += vl;
223→        pOut4 += vl;
224→
225→        rowCnt--;
226→    }
